import type { Spell } from '../../types';

export const ALL_SPELLS: Spell[] = [
  // CANTRIPS
  { id: 'fire-bolt', name: 'Fire Bolt', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn\'t being worn or carried.\n\nThis spell\'s damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).', classes: ['sorcerer', 'wizard'], damageType: 'fire', tags: ['damage', 'ranged'] },
  { id: 'eldritch-blast', name: 'Eldritch Blast', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 force damage.\n\nThe spell creates more than one beam when you reach higher levels: two beams at 5th level, three beams at 11th level, and four beams at 17th level. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.', classes: ['warlock'], damageType: 'force', tags: ['damage', 'ranged'] },
  { id: 'sacred-flame', name: 'Sacred Flame', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['cleric'], damageType: 'radiant', savingThrow: 'dex', tags: ['damage'] },
  { id: 'guidance', name: 'Guidance', level: 0, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check. The spell then ends.', classes: ['cleric', 'druid'], tags: ['buff', 'utility'] },
  { id: 'mage-hand', name: 'Mage Hand', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.\n\nYou can use your action to control the hand. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it.\n\nThe hand can\'t attack, activate magic items, or carry more than 10 pounds.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'prestidigitation', name: 'Prestidigitation', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S'], duration: 'Up to 1 hour', concentration: false, ritual: false, description: 'This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within range: You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor. You instantaneously light or snuff out a candle, a torch, or a small campfire. You instantaneously clean or soil an object no larger than 1 cubic foot. You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour. You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour. You create a nonmagical trinket or an illusory image that can fit in your hand and that lasts until the end of your next turn.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'minor-illusion', name: 'Minor Illusion', level: 0, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['S', 'M'], materialComponent: 'a bit of fleece', duration: '1 minute', concentration: false, ritual: false, description: 'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again.\n\nIf you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else\'s voice, a lion\'s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.\n\nIf you create an image of an object—such as a chair, muddy footprints, or a small chest—it must be no larger than a 5-foot cube. The image can\'t create sound, light, smell, or any other sensory effect.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'illusion'] },
  { id: 'vicious-mockery', name: 'Vicious Mockery', level: 0, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a Wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.\n\nThis spell\'s damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).', classes: ['bard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'debuff'] },
  { id: 'toll-the-dead', name: 'Toll the Dead', level: 0, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You point at one creature you can see within range, and the sound of a dolorous bell fills the air around it for a moment. The target must succeed on a Wisdom saving throw or take 1d8 necrotic damage. If the target is missing any of its hit points, it instead takes 1d12 necrotic damage.\n\nThe spell\'s damage increases by one die when you reach 5th level (2d8 or 2d12), 11th level (3d8 or 3d12), and 17th level (4d8 or 4d12).', classes: ['cleric', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'wis', tags: ['damage'] },
  { id: 'shillelagh', name: 'Shillelagh', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'mistletoe, a shamrock leaf, and a club or quarterstaff', duration: '1 minute', concentration: false, ritual: false, description: 'The wood of a club or quarterstaff you are holding is imbued with nature\'s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon\'s damage die becomes a d8. The weapon also becomes magical, if it isn\'t already. The spell ends if you cast it again or if you let go of the weapon.', classes: ['druid'], tags: ['buff'] },
  { id: 'thunderclap', name: 'Thunderclap', level: 0, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self (5-foot radius)', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a burst of thunderous sound that can be heard up to 100 feet away. Each creature within range, other than you, must succeed on a Constitution saving throw or take 1d6 thunder damage.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'ray-of-frost', name: 'Ray of Frost', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'wizard'], damageType: 'cold', tags: ['damage', 'control'] },
  { id: 'acid-splash', name: 'Acid Splash', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl a bubble of acid. Choose one creature you can see within range, or choose two creatures you can see within range that are within 5 feet of each other. A target must succeed on a Dexterity saving throw or take 1d6 acid damage.\n\nThis spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['sorcerer', 'wizard'], damageType: 'acid', savingThrow: 'dex', tags: ['damage'] },
  { id: 'chill-touch', name: 'Chill Touch', level: 0, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack against the creature to assail it with the chill of the grave. On a hit, the target takes 1d8 necrotic damage, and it can\'t regain hit points until the start of your next turn. Until then, the hand clings to the target.\n\nIf you hit an undead target, it also has disadvantage on attack rolls against you until the end of your next turn.\n\nThis spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', tags: ['damage', 'debuff'] },
  { id: 'spare-the-dying', name: 'Spare the Dying', level: 0, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.', classes: ['cleric'], tags: ['healing', 'utility'] },
  { id: 'light', name: 'Light', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'M'], materialComponent: 'a firefly or phosphorescent moss', duration: '1 hour', concentration: false, ritual: false, description: 'You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like. Completely covering the object with something opaque blocks the light. The spell ends if you cast it again or dismiss it as an action.\n\nIf you target an object held or worn by a hostile creature, that creature must succeed on a Dexterity saving throw to avoid the spell.', classes: ['bard', 'cleric', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'thaumaturgy', name: 'Thaumaturgy', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V'], duration: 'Up to 1 minute', concentration: false, ritual: false, description: 'You manifest a minor wonder, a sign of supernatural power, within range. You create one of the following magical effects within range: Your voice booms up to three times as loud as normal for 1 minute. You cause flames to flicker, brighten, dim, or change color for 1 minute. You cause harmless tremors in the ground for 1 minute. You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers. You instantaneously cause an unlocked door or window to fly open or slam shut. You alter the appearance of your eyes for 1 minute.', classes: ['cleric'], tags: ['utility'] },
  { id: 'druidcraft', name: 'Druidcraft', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Whispering to the spirits of nature, you create one of the following effects within range: You create a tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. You instantly make a flower blossom, a seed pod open, or a leaf bud bloom. You create an instantaneous, harmless sensory effect, such as falling leaves, a puff of wind, the sound of a small animal, or the faint odor of skunk. You light or snuff out a candle, a torch, or a small campfire.', classes: ['druid'], tags: ['utility'] },
  // LEVEL 1
  { id: 'magic-missile', name: 'Magic Missile', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'force', tags: ['damage'] },
  { id: 'burning-hands', name: 'Burning Hands', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot cone)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 3d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire ignites any flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'cure-wounds', name: 'Cure Wounds', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger'], tags: ['healing'] },
  { id: 'healing-word', name: 'Healing Word', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.', classes: ['bard', 'cleric', 'druid'], tags: ['healing'] },
  { id: 'shield', name: 'Shield', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 reaction, which you take when you are hit by an attack or targeted by the magic missile spell', range: 'Self', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'reaction'] },
  { id: 'mage-armor', name: 'Mage Armor', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a piece of cured leather', duration: '8 hours', concentration: false, ritual: false, description: 'You touch a willing creature who isn\'t wearing armor, and a protective magical force surrounds it until the spell ends. The target\'s base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'buff'] },
  { id: 'sleep', name: 'Sleep', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of fine sand, rose petals, or a cricket', duration: '1 minute', concentration: false, ritual: false, description: 'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points (ignoring unconscious creatures).\n\nStarting with the creature that has the lowest current hit points, each creature affected by this spell falls unconscious until the spell ends, the sleeper takes damage, or someone uses an action to shake or slap the sleeper awake.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'charm-person', name: 'Charm Person', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'You attempt to charm a humanoid you can see within range. It must make a Wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance. When the spell ends, the creature knows it was charmed by you.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', classes: ['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'social'] },
  { id: 'thunderwave', name: 'Thunderwave', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot cube)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a Constitution saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half as much damage and isn\'t pushed.\n\nIn addition, unsecured objects that are completely within the area of effect are automatically pushed 10 feet away from you by the spell\'s effect, and the spell emits a thunderous boom audible out to 300 feet.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'bless', name: 'Bless', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a sprinkling of holy water', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', classes: ['cleric', 'paladin'], tags: ['buff'] },
  { id: 'hex', name: 'Hex', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 bonus action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'the petrified eye of a newt', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 necrotic damage to the target whenever you hit it with an attack. Also, choose one ability when you cast the spell. The target has disadvantage on ability checks made with the chosen ability.\n\nIf the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to curse a new creature.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', classes: ['warlock'], damageType: 'necrotic', tags: ['debuff', 'damage'] },
  { id: 'hunters-mark', name: "Hunter's Mark", level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 bonus action', range: '90 feet', components: ['V'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any Wisdom (Perception) or Wisdom (Survival) check you make to find it. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to mark a new creature.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', classes: ['ranger'], tags: ['damage', 'buff'] },
  { id: 'find-familiar', name: 'Find Familiar', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 hour', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: '10 gp worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier', duration: 'Instantaneous', concentration: false, ritual: true, description: 'You gain the service of a familiar, a spirit that takes an animal form you choose: bat, cat, crab, frog (toad), hawk, lizard, octopus, owl, poisonous snake, fish (quipper), rat, raven, sea horse, spider, or weasel. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of a beast.', classes: ['wizard'], tags: ['utility'] },
  { id: 'divine-smite', name: 'Divine Smite', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'The first time you hit with a melee weapon attack during this spell\'s duration, your weapon flares with white-hot intensity, and the attack deals an extra 2d8 radiant damage to the target. The spell then ends. If you hit a fiend or an undead, the attack deals an extra 1d8 radiant damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the extra damage increases by 1d8 for each slot level above 1st (maximum 5d8). The damage increases by another 1d8 if the target is an undead or a fiend (maximum 6d8).', classes: ['paladin'], damageType: 'radiant', tags: ['damage'] },
  { id: 'guiding-bolt', name: 'Guiding Bolt', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack against the target. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage, thanks to the mystical dim light glittering on the target until then.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['cleric'], damageType: 'radiant', tags: ['damage', 'buff'] },
  { id: 'inflict-wounds', name: 'Inflict Wounds', level: 1, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', classes: ['cleric'], damageType: 'necrotic', tags: ['damage'] },
  { id: 'detect-magic', name: 'Detect Magic', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: true, description: 'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'identify', name: 'Identify', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pearl worth at least 100 gp and an owl feather', duration: 'Instantaneous', concentration: false, ritual: true, description: 'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any. You learn whether any spells are affecting the item and what they are. If the item was created by a spell, you learn which spell created it.\n\nIf you instead touch a creature throughout the casting, you learn what spells, if any, are currently affecting it.', classes: ['bard', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'sanctuary', name: 'Sanctuary', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a small silver mirror', duration: '1 minute', concentration: false, ritual: false, description: 'You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell. This spell doesn\'t protect the warded creature from area effects, such as the explosion of a fireball.\n\nIf the warded creature makes an attack, casts a spell that affects an enemy, or deals damage to another creature, this spell ends.', classes: ['cleric'], savingThrow: 'wis', tags: ['defense', 'utility'] },
  // LEVEL 2
  { id: 'misty-step', name: 'Misty Step', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'scorching-ray', name: 'Scorching Ray', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several. Make a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you create one additional ray for each slot level above 2nd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', tags: ['damage'] },
  { id: 'hold-person', name: 'Hold Person', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, straight piece of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a humanoid that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd.', classes: ['bard', 'cleric', 'druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'invisibility', name: 'Invisibility', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an eyelash encased in gum arabic', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person. The spell ends for a target that attacks or casts a spell.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['stealth', 'utility'] },
  { id: 'spiritual-weapon', name: 'Spiritual Weapon', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier.\n\nAs a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for every two slot levels above 2nd.', classes: ['cleric'], damageType: 'force', tags: ['damage', 'bonus-action'] },
  { id: 'shatter', name: 'Shatter', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a chip of mica', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much damage on a successful one. A creature made of inorganic material such as stone, crystal, or metal has disadvantage on this saving throw.\n\nA nonmagical object that isn\'t being worn or carried also takes the damage if it\'s in the spell\'s area.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'lesser-restoration', name: 'Lesser Restoration', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a creature and can end either one disease or one condition afflicting it. The condition can be blinded, deafened, paralyzed, or poisoned.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger'], tags: ['healing', 'utility'] },
  { id: 'prayer-of-healing', name: 'Prayer of Healing', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '10 minutes', range: '30 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.', classes: ['cleric'], tags: ['healing', 'aoe'] },
  { id: 'mirror-image', name: 'Mirror Image', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it\'s impossible to track which image is real. You can use your action to dismiss the illusory duplicates.\n\nEach time a creature targets you with an attack during the spell\'s duration, roll a d20 to determine whether the attack instead targets one of your duplicates.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['defense', 'illusion'] },
  { id: 'blur', name: 'Blur', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn\'t rely on sight, as with blindsight, or can see through illusions, as with truesight.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'illusion'] },
  { id: 'moonbeam', name: 'Moonbeam', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'several seeds of any moonseed plant and a piece of opalescent feldspar', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A silvery beam of pale light shines down in a 5-foot-radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder.\n\nWhen a creature enters the spell\'s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a Constitution saving throw. It takes 2d10 radiant damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d10 for each slot level above 2nd.', classes: ['druid'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },
  // LEVEL 3
  { id: 'fireball', name: 'Fireball', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny ball of bat guano and sulfur', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a Dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire spreads around corners. It ignites flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'lightning-bolt', name: 'Lightning Bolt', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (100-foot line)', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur and a rod of amber, crystal, or glass', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one.\n\nThe lightning ignites flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'counterspell', name: 'Counterspell', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 reaction, which you take when you see a creature within 60 feet of you casting a spell', range: '60 feet', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a success, the creature\'s spell fails and has no effect.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the interrupted spell has no effect if its level is less than or equal to the level of the spell slot you used.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['reaction', 'defense', 'counter'] },
  { id: 'dispel-magic', name: 'Dispel Magic', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose one creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a successful check, the spell ends.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you automatically end the effects of a spell on the target if the spell\'s level is equal to or less than the level of the spell slot you used.', classes: ['bard', 'cleric', 'druid', 'paladin', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'counter'] },
  { id: 'fly', name: 'Fly', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a wing feather from any bird', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'haste', name: 'Haste', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a shaving of licorice root', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a willing creature that you can see within range. Until the spell ends, the target\'s speed is doubled, it gains a +2 bonus to AC, it has advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action.\n\nWhen the spell ends, the target can\'t move or take actions until after its next turn, as a wave of lethargy sweeps over it.', classes: ['sorcerer', 'wizard'], tags: ['buff', 'control'] },
  { id: 'spirit-guardians', name: 'Spirit Guardians', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot radius)', components: ['V', 'S', 'M'], materialComponent: 'a holy symbol', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish.\n\nWhen you cast this spell, you can designate any number of creatures you can see to be unaffected by it. An affected creature\'s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a Wisdom saving throw. On a failed save, the creature takes 3d8 radiant damage (if you are good or neutral) or 3d8 necrotic damage (if you are evil). On a successful save, the creature takes half as much damage.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d8 for each slot level above 3rd.', classes: ['cleric'], damageType: 'radiant', savingThrow: 'wis', tags: ['damage', 'aoe', 'control'] },
  { id: 'revivify', name: 'Revivify', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'diamonds worth 300 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can\'t return to life a creature that has died of old age, nor can it restore any missing body parts.', classes: ['cleric', 'druid', 'paladin'], tags: ['healing', 'utility'] },
  { id: 'mass-healing-word', name: 'Mass Healing Word', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.', classes: ['cleric'], tags: ['healing', 'aoe'] },
  // LEVEL 4
  { id: 'banishment', name: 'Banishment', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'an item distasteful to the target', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to send one creature that you can see within range to another place of existence. The target must succeed on a Charisma saving throw or be banished.\n\nIf the target is native to the plane of existence you\'re on, you banish the target to a harmless demiplane. While there, the target is incapacitated. The target remains there until the spell ends, at which point the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.', atHigherLevels: 'When you cast this spell using a spell slot of 5th level or higher, you can target one additional creature for each slot level above 4th.', classes: ['cleric', 'paladin', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'cha', tags: ['control'] },
  { id: 'polymorph', name: 'Polymorph', level: 4, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a caterpillar cocoon', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a Wisdom saving throw to avoid the effect. A shapechanger automatically succeeds on this saving throw.\n\nThe transformation lasts for the duration, or until the target drops to 0 hit points or dies. The new form can be any beast whose challenge rating is equal to or less than the target\'s (or the target\'s level, if it doesn\'t have a challenge rating). The target\'s game statistics, including mental ability scores, are replaced by the statistics of the chosen beast.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'utility'] },
  { id: 'dimension-door', name: 'Dimension Door', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '500 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as "200 feet straight downward" or "upward to the northwest at a 45-degree angle, 300 feet."\n\nYou can bring along objects as long as their weight doesn\'t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'greater-invisibility', name: 'Greater Invisibility', level: 4, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['stealth', 'buff'] },
  // LEVEL 5
  { id: 'hold-monster', name: 'Hold Monster', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, straight piece of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. This spell has no effect on undead. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, you can target one additional creature for each slot level above 5th.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'cone-of-cold', name: 'Cone of Cold', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (60-foot cone)', components: ['V', 'S', 'M'], materialComponent: 'a small crystal or glass cone', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a Constitution saving throw. A creature takes 8d8 cold damage on a failed save, or half as much damage on a successful one.\n\nA creature killed by this spell becomes a frozen statue until it thaws.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.', classes: ['sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'mass-cure-wounds', name: 'Mass Cure Wounds', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the healing increases by 1d8 for each slot level above 5th.', classes: ['bard', 'cleric', 'druid'], tags: ['healing', 'aoe'] },
  { id: 'wall-of-force', name: 'Wall of Force', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of powder made by crushing a clear gemstone', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'An invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-by-10-foot panels.', classes: ['wizard'], tags: ['control', 'utility'] },
  { id: 'flame-strike', name: 'Flame Strike', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'pinch of sulfur', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A vertical column of divine fire roars down from the heavens in a location you specify. Each creature in a 10-foot-radius, 40-foot-high cylinder centered on a point within range must make a Dexterity saving throw. A creature takes 4d6 fire damage and 4d6 radiant damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the fire damage or the radiant damage (your choice) increases by 1d6 for each slot level above 5th.', classes: ['cleric'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  // LEVEL 6
  { id: 'chain-lightning', name: 'Chain Lightning', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur; a piece of amber, glass, or a crystal rod; and three silver pins', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a bolt of lightning that arcs toward a target of your choice that you can see within range. Three bolts then leap from that target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts.\n\nA target must make a Dexterity saving throw. The target takes 10d8 lightning damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 7th level or higher, one additional bolt leaps from the first target to another target for each slot level above 6th.', classes: ['sorcerer', 'wizard'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'true-seeing', name: 'True Seeing', level: 6, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an ointment for the eyes that costs 25 gp; is made from mushroom powder, saffron, and fat; and is consumed by the spell', duration: '1 hour', concentration: false, ritual: false, description: 'You give the willing creature you touch the ability to see things as they actually are. For the duration, the creature has truesight, notices secret doors hidden by magic, and can see into the Ethereal Plane, all out to a range of 120 feet.', classes: ['bard', 'cleric', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'detection'] },
  // LEVEL 7
  { id: 'finger-of-death', name: 'Finger of Death', level: 7, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You send negative energy coursing through a creature that you can see within range, causing it searing pain. The target must make a Constitution saving throw. It takes 7d8 + 30 necrotic damage on a failed save, or half as much damage on a successful one.\n\nA humanoid killed by this spell rises at the start of your next turn as a zombie that is permanently under your command, following your verbal orders to the best of its ability.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage'] },
  { id: 'teleport', name: 'Teleport', level: 7, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell instantly transports you and up to eight willing creatures of your choice that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be able to fit entirely inside a 10-foot cube, and it can\'t be held or carried by an unwilling creature.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['movement', 'utility'] },
  // LEVEL 8
  { id: 'power-word-stun', name: 'Power Word Stun', level: 8, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Until ended', concentration: false, ritual: false, description: 'You speak a word of power that overwhelms the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect.\n\nThe stunned target must make a Constitution saving throw at the end of each of its turns. On a successful save, the stunning effect ends.', classes: ['sorcerer', 'warlock', 'wizard'], savingThrow: 'con', tags: ['control'] },
  // LEVEL 9
  { id: 'wish', name: 'Wish', level: 9, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires.\n\nThe basic use of this spell is to duplicate any other spell of 8th level or lower. You don\'t need to meet any requirements in that spell, including costly components. The spell simply takes effect. Alternatively, you can create one of the following effects of your choice: You create one object of up to 25,000 gp in value that isn\'t a magic item. The object can be no more than 300 feet in any dimension, and it appears in an unoccupied space you can see on the ground. You allow up to twenty creatures that you can see to regain all hit points, and you end all effects on them described in the greater restoration spell. You grant up to ten creatures that you can see immunity to a single spell or other magical effect for 8 hours. You undo a single recent event by forcing a reroll of any roll made within the last round (including your last turn). Reality reshapes itself to accommodate the new result.', classes: ['sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'power-word-kill', name: 'Power Word Kill', level: 9, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You utter a word of power that can compel one creature you can see within range to die instantly. If the creature you choose has 100 hit points or fewer, it dies. Otherwise, the spell has no effect.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['damage'] },
  { id: 'meteor-swarm', name: 'Meteor Swarm', level: 9, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '1 mile', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a Dexterity saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much damage on a successful one. A creature in the area of more than one fiery burst is affected only once. The spell damages objects in the area and ignites flammable objects that aren\'t being worn or carried.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
];

export function getSpell(id: string): Spell | undefined {
  return ALL_SPELLS.find(s => s.id === id);
}

export function getSpellsByClass(classId: string): Spell[] {
  return ALL_SPELLS.filter(s => s.classes.includes(classId));
}
